// Use firebase-admin with the Firebase CLI's refresh token
const { execSync } = require\('child_process'\);
const fs = require\('fs'\);
const path = require\('path'\);
const os = require\('os'\);

// Find Firebase CLI config to get the refresh token
const configDir = path.join\(os.homedir\(\), '.config', 'configstore'\);
let configPath = path.join\(configDir, 'firebase-tools.json'\);
if \(!fs.existsSync\(configPath\)\) {
  // Windows alternative
  const winPath = path.join\(os.homedir\(\), '.config', 'configstore', 'firebase-tools.json'\);
  if \(fs.existsSync\(winPath\)\) configPath = winPath;
}
console.log\('Config path:', configPath\);
console.log\('Exists:', fs.existsSync\(configPath\)\);
